matched.bodyText:
:first-child 
 {margin-top:0; 
 padding-top:0} 
.content-td h1 
 {font-size:1.3em; 
 font-weight:bold; 
 line-height:25px; 
 margin-top:20px; 
 margin-bottom:5px} 
.content-td h1 + h2 
 {margin-top:0!important} 
.content-td h2 + h1 
 {margin-top:0!important} 
.content-td h2 
 {font-size:1.1em; 
 font-weight:bold; 
 margin:20px 0 5px} 
.content-td h3, .content-td h4, .content-td h5 
 {font-size:13px; 
 font-weight:bold; 
 margin-bottom:5px} 
.content-td p 
 {margin:0 0 15px 0} 
.content-td p.no-margin 
 {margin:0; 
 min-height:15px} 
.content-td p img, .content-td h1 img, .content-td h2 img, .content-td li img, .content-td .intercom-h2b-button img 
 {margin:0; 
 padding:0; 
 vertical-align:top} 
.content-td a 
 {color:#1251ba; 
 text-decoration:underline} 
.content-td .messenger-card .link 
 {margin-bottom:25px} 
.content-td strong 
 {color:#606060} 
.content-td ol, .content-td ul 
 {margin:0 0 20px 40px; 
 padding:0; 
 list-style:disc} 
.content-td ol 
 {list-style:decimal} 
.content-td ol li, .content-td ul li 
 {margin:5px 0} 
.content-td blockquote 
 {padding:10px 0; 
 margin:10px 0; 
 font-style:italic} 
.content-td blockquote a 
 {color:#8C8C8C} 
.content-td img 
 {max-width:100%; 
 margin:15px 0 15px} 
.content-td .intercom-container 
 {margin-bottom:16px} 
.content-td hr 
 {border:none; 
 border-top:1px solid #DDD; 
 border-bottom:0; 
 margin:20px 0} 
.content-td table th 
 {font-weight:bold; 
 background:#F6F6F6} 
.content-td table td, .content-td table th 
 {padding:7px 10px; 
 border:1px solid #DADADA; 
 text-align:left; 
 vertical-align:top} 
.content-td table 
 {margin-bottom:20px; 
 border-collapse:collapse; 
 border-spacing:0} 
.content-td table.intercom-container.intercom-align-center 
 {margin-left:auto; 
 margin-right:auto} 
.content-td table.intercom-container td 
 {border:none; 
 padding:0; 
 margin:0} 
.content-td a.reply-in-messenger-button 
 {background-color:#286efa; 
 color:white; 
 padding:6px 25px; 
 margin:0px 0 16px 0; 
 border-radius:20px; 
 text-decoration:none; 
 display:inline-block; 
 font-size:12px} 
.content-td p.reply-in-messenger-message 
 {color:#8c8c8c; 
 font-size:12px; 
 margin:0} 
table.ratings, .content-td .messenger-card 
 {border-collapse:separate; 
 border-spacing:0; 
 table-layout:fixed; 
 border-radius:5px; 
 border:1px solid #dadfe3; 
 margin-bottom:0} 
table.fin-reply-options 
 {border-collapse:separate; 
 border-spacing:0; 
 table-layout:fixed; 
 margin:0} 
td .fin-reply-button 
 {color:#0A2C93; 
 text-decoration:none; 
 border:1px solid #FFFFFF!important; 
 border-radius:40px; 
 background-color:#E7ECFE; 
 padding:8px 16px; 
 display:block; 
 margin-right:10px} 
td .fin-reply-button-layout-updated 
 {color:#0A2C93; 
 text-decoration:none; 
 border-radius:40px; 
 background-color:#E7ECFE; 
 padding:8px 16px; 
 display:block} 
.content-td table.ratings 
 {width:260px; 
 padding:16px 0} 
table.ratings 
 {padding:16px 0} 
.content-td .ratings table img 
 {margin:0} 
.align_top 
 {vertical-align:top} 
.align_center 
 {margin:0 auto} 
.smiley 
 {padding:4px} 
.divider 
 {border:none; 
 height:1px; 
 color:#f0f0f0; 
 background-color:#f0f0f0; 
 margin:0} 
.feedback-text 
 {margin-bottom:0.3em; 
 margin-top:0} 
.deemphasized_text 
 {color:#8c8c8c} 
.sent_to_text 
 {font-weight:bold} 
.dark_text 
 {color:#222} 
.light_text 
 {color:#999} 
.align_middle 
 {vertical-align:middle!important} 
.history .history_content 
 {font-style:normal; 
 padding-top:1px; 
 border-left:1px #ccc solid; 
 margin:0 0 0 .8ex; 
 padding-left:1ex} 
.history .history_content > *:last-child 
 {margin-bottom:0} 
.powered_by_badge 
 {font-size:14px} 
.powered_by_link 
 {color:#8c8c8c; 
 font-weight:bold; 
 text-decoration:none} 
.email_signature 
 {font-size:14px; 
 line-height:20px} 
.email_signature .container 
 {} 
.email_signature th 
 {font-weight:normal} 
.email_signature p, .email_signature h1, .email_signature h2 
 {margin:0; 
 padding:0; 
 text-align:start} 
.history 
 {color:#500050} 
.ticket_card 
 {border:1px solid #E1E1E1; 
 border-radius:8px; 
 width:100%; 
 max-width:570px; 
 word-wrap:break-word} 
.ticket_card .app_logo 
 {width:100%; 
 padding:18px 40px; 
 border-bottom:1px solid #E1E1E1} 
.ticket_card .app_logo img 
 {height:26px!important; 
 max-height:26px!important; 
 max-width:100%} 
.ticket_card .body 
 {padding:28px 40px; 
 font-size:14px; 
 font-weight:400; 
 line-height:16px; 
 width:100%} 
.collapsed_ticket_card .title, .ticket_card .title 
 {font-size:18px; 
 font-weight:700; 
 line-height:24px} 
.ticket_card .ticket_state_description 
 {font-size:16px; 
 line-height:20px; 
 padding-bottom:24px} 
.ticket_card .ticket_state_step 
 {border-radius:8px; 
 height:4px; 
 margin-bottom:8px} 
.ticket_card .ticket_state_submitted 
 {background-color:#334bfa; 
 border-color:#334bfa} 
.ticket_card .ticket_state_in_progress 
 {background-color:#b24d00; 
 border-color:#b24d00} 
.ticket_card .ticket_state_waiting_on_customer 
 {background-color:#db0629; 
 border-color:#db0629}
